describe('buildContext()', () => {
  it('returns valid AdapterContext with correct directory when meshCore resolves a path', () => {
    // Purpose: verifies the complete happy path — meshCore.getProjectPath() is called
    // with the agentId extracted from the subject, and the result is placed in
    // context.agent.directory.
    const meshCore = createMockMeshCore({
      '01JN4M2X5SZMHXP3EZFM9DWRXFK': '/home/user/projectB',
    });
    const deps = createMinimalDeps({ meshCore });
    const manager = new AdapterManager(mockRegistry, '/tmp/adapters.json', deps);

    const ctx = manager.buildContext('relay.agent.01JN4M2X5SZMHXP3EZFM9DWRXFK');

    expect(ctx).toEqual({
      agent: {
        directory: '/home/user/projectB',
        runtime: 'claude-code',
      },
    });
    expect(meshCore.getProjectPath).toHaveBeenCalledWith('01JN4M2X5SZMHXP3EZFM9DWRXFK');
  });

  it('returns undefined when agentId not found in Mesh', () => {
    // Purpose: verifies that when getProjectPath() returns undefined (unknown agent),
    // buildContext() propagates undefined rather than returning a partial context.
    const meshCore = createMockMeshCore({});
    const deps = createMinimalDeps({ meshCore });
    const manager = new AdapterManager(mockRegistry, '/tmp/adapters.json', deps);

    const ctx = manager.buildContext('relay.agent.UNKNOWN_AGENT_ULID');

    expect(ctx).toBeUndefined();
  });

  it('returns undefined when meshCore is not injected (backward compat)', () => {
    // Purpose: verifies that adapters without Mesh integration work as before —
    // no meshCore means no CWD override, which is safe and expected.
    const deps = createMinimalDeps({ meshCore: undefined });
    const manager = new AdapterManager(mockRegistry, '/tmp/adapters.json', deps);

    const ctx = manager.buildContext('relay.agent.01JN4M2X');

    expect(ctx).toBeUndefined();
  });

  it('returns undefined for non-agent subjects (relay.human.*)', () => {
    // Purpose: verifies that BindingRouter messages (relay.human.*) are not
    // matched by buildContext(), which would be incorrect.
    const meshCore = createMockMeshCore({ 'some-id': '/path/to/project' });
    const deps = createMinimalDeps({ meshCore });
    const manager = new AdapterManager(mockRegistry, '/tmp/adapters.json', deps);

    expect(manager.buildContext('relay.human.console.client-1')).toBeUndefined();
    expect(manager.buildContext('relay.system.pulse.sched-1')).toBeUndefined();
    expect(manager.buildContext('relay.inbox.some-agent')).toBeUndefined();
  });

  it('correctly parses relay.agent.{agentId} with nested subject segments', () => {
    // Purpose: verifies that agentIds containing dots or unusual characters are
    // correctly extracted via split('.')[2] — specifically that the ULID segment
    // is always index 2.
    const meshCore = createMockMeshCore({
      '01JN4M2X5SZMHXP3EZFM9DWRXFK': '/path/to/agent',
    });
    const deps = createMinimalDeps({ meshCore });
    const manager = new AdapterManager(mockRegistry, '/tmp/adapters.json', deps);

    // Normal ULID-style agentId
    const ctx = manager.buildContext('relay.agent.01JN4M2X5SZMHXP3EZFM9DWRXFK');
    expect(ctx?.agent.directory).toBe('/path/to/agent');
  });
});
```

## Helper function needed

The existing test uses `readFile` mocks for config loading. Add a `createMinimalDeps` helper that creates a deps object without triggering `initialize()` (since `buildContext()` does not require initialization):

```typescript
function createMinimalDeps(overrides?: Partial<AdapterManagerDeps>): AdapterManagerDeps {
  return {
    agentManager: {
      ensureSession: vi.fn(),
      sendMessage: vi.fn(),
    } as unknown as ClaudeCodeAgentManagerLike,
    traceStore: {
      insertSpan: vi.fn(),
      updateSpan: vi.fn(),
    },
    ...overrides,
  };
}
```

Note: `buildContext()` is a synchronous method that only accesses `this.deps`, so no `await adapterManager.initialize()` is needed for these tests.

