describe('per-agentId queue (concurrency safety)', () => {
  it('serializes concurrent deliver() calls to the same agentId', async () => {
    // Purpose: the SDK disallows concurrent query() calls on the same session.
    // This test proves that two simultaneous deliver() calls to the same agentId
    // are serialized: the second sendMessage starts only after the first completes.
    const callOrder: string[] = [];
    let resolveFirst!: () => void;

    // First sendMessage hangs until resolveFirst() is called
    const firstStream = (async function* () {
      callOrder.push('first:start');
      await new Promise<void>((r) => { resolveFirst = r; });
      callOrder.push('first:end');
      yield { type: 'done', data: {} } as StreamEvent;
    })();

    // Second sendMessage resolves immediately
    const secondStream = (async function* () {
      callOrder.push('second:start');
      yield { type: 'done', data: {} } as StreamEvent;
    })();

    vi.mocked(agentManager.sendMessage)
      .mockReturnValueOnce(firstStream)
      .mockReturnValueOnce(secondStream);

    await adapter.start(relay);

    const envelope1 = createTestEnvelope({ subject: 'relay.agent.SAME_AGENT' });
    const envelope2 = createTestEnvelope({ subject: 'relay.agent.SAME_AGENT', id: 'msg-002' });

    // Dispatch both concurrently
    const p1 = adapter.deliver(envelope1.subject, envelope1);
    const p2 = adapter.deliver(envelope2.subject, envelope2);

    // Let the event loop tick so first call can start
    await Promise.resolve();
    await Promise.resolve();

    // First has started, second has NOT started yet
    expect(callOrder).toContain('first:start');
    expect(callOrder).not.toContain('second:start');

    // Release the first call
    resolveFirst();
    await p1;
    await p2;

    // Now both have completed in order
    expect(callOrder).toEqual(['first:start', 'first:end', 'second:start']);
  });

  it('does NOT block concurrent deliver() calls to DIFFERENT agentIds', async () => {
    // Purpose: queue isolation — two different agents can be contacted in parallel.
    // Blocking cross-agent messages would be a performance regression.
    let resolveA!: () => void;
    let resolveB!: () => void;
    let aStarted = false;
    let bStarted = false;

    const streamA = (async function* () {
      aStarted = true;
      await new Promise<void>((r) => { resolveA = r; });
      yield { type: 'done', data: {} } as StreamEvent;
    })();

    const streamB = (async function* () {
      bStarted = true;
      await new Promise<void>((r) => { resolveB = r; });
      yield { type: 'done', data: {} } as StreamEvent;
    })();

    vi.mocked(agentManager.sendMessage)
      .mockReturnValueOnce(streamA)
      .mockReturnValueOnce(streamB);

    await adapter.start(relay);

    const envelopeA = createTestEnvelope({ subject: 'relay.agent.AGENT_A' });
    const envelopeB = createTestEnvelope({ subject: 'relay.agent.AGENT_B', id: 'msg-B' });

    const pA = adapter.deliver(envelopeA.subject, envelopeA);
    const pB = adapter.deliver(envelopeB.subject, envelopeB);

    // Allow both to start
    await Promise.resolve();
    await Promise.resolve();

    // Both should have started independently
    expect(aStarted).toBe(true);
    expect(bStarted).toBe(true);

    resolveA();
    resolveB();
    await pA;
    await pB;
  });
});
```

